        } else if (ch === '#') {
            len *= 2;
        } else if (ch === '%') {
            // Reversal doesn't change length
        } else {
            len++;
        }
    }

    if (k < 0 || k >= len) {
        return '.';
    }

    let rev = false;

    for (let i = n - 1; i >= 0; i--) {
        const ch = s[i];
        if (ch === '*') {
            len++;
