            let half = Math.floor(len / 2);
            if (k >= half) {
                k -= half;
            }
            len = half;
        } else {
            if (rev) {
                if (k === 0) {
                    return ch;
                } else {
                    k--;
                    len--;
                }
            } else {
                if (k === len - 1) {
                    return ch;
                } else {
                    len--;
                }
            }
        }
    }

    return '.';
}
