function solve(s: string, k: number): string {
    const n = s.length;
    const lens: number[] = new Array(n);
    let curLen = 0;

    for (let i = 0; i < n; i++) {
        const c = s[i];
        if (c === '*') {
            curLen = Math.max(0, curLen - 1);
        } else if (c === '#') {
            curLen *= 2;
        } else if (c === '%') {
            // Reversal doesn't change length
        } else {
            curLen++;
        }
        lens[i] = curLen;
    }

    const totalLen = lens[n-1];
    if (k >= totalLen) {
        return '.';
    }

    let currentK = k;
    let rev = false;

    for (let i = n-1; i >= 0; i--) {
        const op = s[i];
        const currentLen = lens[i];

        if (op === '*') {
            const prevLen = currentLen + 1;
            const pos = rev ? currentLen - 1 - currentK : currentK;
            currentK = pos;
        } else if (op === '#') {
            const prevLen = currentLen / 2;
            const pos = rev ? currentLen - 1 - currentK : currentK;
            if (pos < prevLen) {
                currentK = pos;
            } else {
                currentK = pos - prevLen;
            }
        } else if (op === '%') {
            rev = !rev;
        } else {
            const prevLen = currentLen - 1;
            const pos = rev ? currentLen - 1 - currentK : currentK;
            if (pos === prevLen) {
                return op;
            } else {
                currentK = pos;
            }
        }
    }

    return '.';
}
